// AdvancedFilters - Composant de filtres avancés pour le catalogue
import { Filter, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useState } from 'react';

interface AdvancedFiltersProps {
  genres: string[];
  selectedGenres: string[];
  onGenreChange: (genres: string[]) => void;
  maxPrice?: number;
  selectedPrice?: number;
  onPriceChange?: (price: number) => void;
  availability?: 'all' | 'available' | 'unavailable';
  onAvailabilityChange?: (availability: 'all' | 'available' | 'unavailable') => void;
  isOpen: boolean;
  onClose: () => void;
}

export function AdvancedFilters({
  genres,
  selectedGenres,
  onGenreChange,
  availability = 'all',
  onAvailabilityChange,
  isOpen,
  onClose,
}: AdvancedFiltersProps) {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 bg-black/50 flex items-start pt-20">
      <div className="surface dark:bg-library-dark-secondary w-full sm:w-80 mx-auto rounded-b-2xl shadow-2xl p-6 space-y-6 max-h-[80vh] overflow-y-auto">
        
        {/* En-tête */}
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <Filter className="w-5 h-5 text-library-primary dark:text-library-dark-accent" />
            <h3 className="font-bold text-lg text-primary dark:text-library-dark-light">Filtres</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-muted rounded-lg transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Genres */}
        <div>
          <h4 className="font-semibold text-primary dark:text-library-dark-light mb-3">Genres</h4>
          <div className="space-y-2">
            {genres.map((genre) => (
              <label key={genre} className="flex items-center gap-3 cursor-pointer group">
                <input
                  type="checkbox"
                  checked={selectedGenres.includes(genre)}
                  onChange={(e) => {
                    if (e.target.checked) {
                      onGenreChange([...selectedGenres, genre]);
                    } else {
                      onGenreChange(selectedGenres.filter(g => g !== genre));
                    }
                  }}
                  className="w-4 h-4 rounded border-muted accent-library-primary dark:accent-library-dark-accent"
                />
                <span className="text-sm text-slate-700 dark:text-library-dark-muted group-hover:text-primary dark:group-hover:text-library-dark-light transition-colors">
                  {genre}
                </span>
              </label>
            ))}
          </div>
        </div>

        {/* Disponibilité */}
        <div>
          <h4 className="font-semibold text-primary dark:text-library-dark-light mb-3">Disponibilité</h4>
          <div className="space-y-2">
            {(['all', 'available', 'unavailable'] as const).map((option) => (
              <label key={option} className="flex items-center gap-3 cursor-pointer group">
                <input
                  type="radio"
                  name="availability"
                  value={option}
                  checked={availability === option}
                  onChange={() => onAvailabilityChange?.(option)}
                  className="w-4 h-4 border-muted accent-library-primary dark:accent-library-dark-accent"
                />
                <span className="text-sm text-slate-700 dark:text-library-dark-muted group-hover:text-primary dark:group-hover:text-library-dark-light transition-colors">
                  {option === 'all' ? 'Tous' : option === 'available' ? 'Disponibles' : 'Indisponibles'}
                </span>
              </label>
            ))}
          </div>
        </div>

        {/* Boutons */}
        <div className="flex gap-2 pt-4 border-t border-muted dark:border-library-dark-secondary">
          <Button
            onClick={() => {
              onGenreChange([]);
              onAvailabilityChange?.('all');
            }}
            variant="outline"
            className="flex-1"
          >
            Réinitialiser
          </Button>
          <Button onClick={onClose} className="flex-1">
            Appliquer
          </Button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';

interface ApiImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  imageKey?: string; 
  src?: string;
  fallback?: string; 
}

export function ApiImage({ imageKey, src, fallback = '/avatar-1.jpg', alt, ...rest }: ApiImageProps) {

  const [url, setUrl] = useState<string | undefined>(() => {
    if (src) return src;

    return undefined;
  });

  useEffect(() => {
    if (src) setUrl(src);

  }, [src]);

  const handleError = (e: React.SyntheticEvent<HTMLImageElement, Event>) => {
    const img = e.currentTarget;
    if (img.src && img.src !== window.location.origin + fallback) {
      img.src = fallback;
    }
  };

  if (!url) return <img src={fallback} alt={alt} {...rest} onError={handleError} />;
  return <img src={url} alt={alt} {...rest} onError={handleError} />;
}

export default ApiImage;

// Composant de navigation inférieure - Barre de navigation fixe en bas de l'écran
import { Home, BookOpen, Users, Newspaper, Bot } from 'lucide-react';
import { useState, useEffect } from 'react';
import type { View } from '@/types';

interface BottomNavigationProps {
  currentView: View;
  onNavigate: (view: View) => void;
}

export function BottomNavigation({ currentView, onNavigate }: BottomNavigationProps) {
  const [justActivated, setJustActivated] = useState<View | null>(null);

  const leftItems = [
    { id: 'home' as View, label: 'Accueil', icon: Home },
    { id: 'catalog' as View, label: 'Catalogue', icon: BookOpen },
  ];

  const rightItems = [
    { id: 'clubs' as View, label: 'Clubs', icon: Users },
    { id: 'news' as View, label: 'Actualités', icon: Newspaper },
  ];

  const isActive = (view: View) => {
    if (view === 'home') return currentView === 'home';
    if (view === 'catalog') return ['catalog', 'book-detail'].includes(currentView);
    if (view === 'clubs') return ['clubs', 'club-detail'].includes(currentView);
    if (view === 'news') return ['news', 'news-detail'].includes(currentView);
    return false;
  };

  const isKoffiActive = currentView === 'ai-chat';

  const handleNavigate = (view: View) => {
    setJustActivated(view);
    onNavigate(view);
  };

  // Reset pop après l'animation
  useEffect(() => {
    if (justActivated) {
      const t = setTimeout(() => setJustActivated(null), 400);
      return () => clearTimeout(t);
    }
  }, [justActivated]);

  const NavButton = ({ item }: { item: { id: View; label: string; icon: React.FC<any> } }) => {
    const active = isActive(item.id);
    const popping = justActivated === item.id;
    const Icon = item.icon;
    return (
      <button
        onClick={() => handleNavigate(item.id)}
        aria-current={active ? 'page' : undefined}
        aria-label={item.label}
        title={item.label}
        role="link"
        className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-xl transition-all duration-200 min-w-0 tap-feedback ${
          active
            ? 'text-[var(--library-accent)]'
            : 'text-[var(--library-muted)] hover:text-[var(--library-text)]'
        }`}
      >
        <div className={`p-1.5 rounded-xl transition-all duration-200 ${
          active ? 'bg-[var(--library-accent)]/12' : ''
        } ${popping ? 'nav-item-active-pop' : active ? 'scale-110' : ''}`}>
          <Icon size={20} strokeWidth={active ? 2.5 : 2} />
        </div>
        <span className={`text-[10px] font-medium leading-none truncate hidden sm:inline transition-opacity ${
          active ? 'opacity-100' : 'opacity-70'
        }`}>
          {item.label}
        </span>
      </button>
    );
  };

  return (
    <nav
      role="navigation"
      aria-label="Navigation principale"
      className="fixed bottom-0 left-0 right-0 z-50 surface backdrop-blur-lg border-t border-[var(--border-color)] safe-area-pb"
    >
      <div className="max-w-3xl mx-auto px-2 sm:px-6">
        <div className="flex items-center h-16 gap-1">

          {leftItems.map(item => <NavButton key={item.id} item={item} />)}

          {/* ── BOUTON KOFFI IA — Centre surélevé ── */}
          <div className="flex-shrink-0 flex flex-col items-center justify-center -mt-5 px-2">
            <button
              onClick={() => handleNavigate('ai-chat' as View)}
              aria-current={isKoffiActive ? 'page' : undefined}
              aria-label="Assistant Koffi IA"
              title="Koffi — Assistant IA"
              className={`relative w-14 h-14 rounded-2xl flex items-center justify-center shadow-medium transition-all duration-300 tap-feedback ${
                isKoffiActive
                  ? 'bg-[var(--library-accent)] scale-105 shadow-elevated'
                  : 'bg-[var(--library-accent)] hover:opacity-90 hover:shadow-elevated hover:-translate-y-0.5'
              } ${justActivated === 'ai-chat' ? 'nav-item-active-pop' : ''}`}
            >
              {/* Halo animé quand actif */}
              {isKoffiActive && (
                <span className="absolute inset-0 rounded-2xl animate-ping bg-[var(--library-accent)]/30 pointer-events-none" />
              )}
              <Bot
                size={26}
                strokeWidth={isKoffiActive ? 2.5 : 2}
                className="text-[var(--library-on-accent)] relative z-10"
              />
            </button>
            <span className={`text-[10px] font-semibold mt-1 leading-none transition-colors ${
              isKoffiActive ? 'text-[var(--library-accent)]' : 'text-[var(--library-muted)]'
            } hidden sm:inline`}>
              Koffi IA
            </span>
            <span className={`sm:hidden mt-0.5 w-1 h-1 rounded-full transition-colors ${
              isKoffiActive ? 'bg-[var(--library-accent)]' : 'bg-transparent'
            }`} />
          </div>

          {rightItems.map(item => <NavButton key={item.id} item={item} />)}

        </div>
      </div>
    </nav>
  );
}

import React from 'react';

interface State {
  hasError: boolean;
  error?: Error | null;
}

export class ErrorBoundary extends React.Component<React.PropsWithChildren<{}>, State> {
  constructor(props: any) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: any) {
    // TODO: send to monitoring service
    // console.error('Unhandled error captured by ErrorBoundary', error, info);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center p-6">
          <div className="max-w-lg w-full surface rounded-xl p-6 text-center">
            <h2 className="text-xl font-semibold mb-2">Une erreur est survenue</h2>
            <p className="text-sm text-muted mb-4">Désolé, quelque chose s'est mal passé. Rechargez la page ou contactez l'administrateur.</p>
            <div className="flex justify-center gap-2">
              <button onClick={() => window.location.reload()} className="px-4 py-2 bg-library-accent text-white rounded">Recharger</button>
            </div>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

export default ErrorBoundary;

// Composant Navbar - Barre de navigation supérieure
import { Bell, ChevronRight, Menu } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';
import type { User } from '@/types';
import { ThemeToggle } from './ThemeToggle';
import ApiImage from './ApiImage';
import { NotificationCenter } from './NotificationCenter';
import { ProfileMenu } from './ProfileMenu';

// Props du composant Navbar
interface NavbarProps {
  user: User; // Utilisateur actuellement connecté
}

/**
 * Navbar - Barre de navigation fixe en haut de l'application
 * Affiche:
 * - Logo de l'application avec lien vers l'accueil
 * - Notifications, sélecteur de thème, infos profil utilisateur
 * - Reste fixe avec support du notch/safe area pour mobiles
 */
export function Navbar({ user }: NavbarProps) {
  const [logoUrl, setLogoUrl] = useState<string>('/logo.jpg');
  const [avatarUrl, setAvatarUrl] = useState<string | null>(user?.avatar ?? null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const notifRef = useRef<HTMLDivElement | null>(null);
  const profileRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    function onDocClick(e: MouseEvent) {
      const target = e.target as Node;
      if (showNotifications && notifRef.current && !notifRef.current.contains(target)) {
        setShowNotifications(false);
      }
      if (showProfileMenu && profileRef.current && !profileRef.current.contains(target)) {
        setShowProfileMenu(false);
      }
    }
    document.addEventListener('click', onDocClick);

    // Logo statique - pas d'appel backend
    // Avatar is taken from `user.avatar` when available; no additional fetch

    return () => {
      document.removeEventListener('click', onDocClick);
    };
  }, [showNotifications, showProfileMenu, user, avatarUrl]);
  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-white/80 dark:bg-library-surface/80 backdrop-blur-xl border-b border-muted transition-all duration-300 shadow-sm dark:shadow-lg adaptive-fg">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">

          {/* Zone logo et branding
              - Lien cliquable vers la page d'accueil
              - Contient le logo et le texte de la bibliothèque
              - Aide à l'identification visuelle de l'application */}
          <a href="/" className="flex items-center gap-3 hover:opacity-80 transition-opacity">
            {/* Logo de l'application */}
            <ApiImage
              src={logoUrl}
              alt="CAEB NATITINGOU"
              className="h-12 w-auto object-contain"
            />
            {/* Texte de branding - Caché sur mobile pour économiser l'espace */}
            <div className="flex flex-col hidden sm:flex">
              <span data-adaptive className="font-display font-bold text-sm text-library-primary dark:text-library-dark-accent leading-none caeb-brand">CAEB</span>
              <span data-adaptive className="text-xs text-library-muted dark:text-library-dark-muted font-medium tracking-wider caeb-brand--solid">Natitingou</span>
            </div>
          </a>

          {/* Zone d'actions - Droite de la navbar
              - Regroupées pour un accès rapide depuis n'importe quelle page
              - Contient: notifications, switch thème, profil utilisateur */}
          <div className="flex items-center gap-1 sm:gap-3">

            {/* Bouton de notifications
                - Affiche une pastille rouge si des notifications existent
                - Prêt à être connecté à un système de notifications réel
                - Visible sur tous les écrans */}
            <div className="relative" ref={notifRef}>
              <button 
                onClick={() => setShowNotifications(v => !v)} 
                className="p-2 text-muted dark:text-library-muted hover:bg-surface-weak dark:hover:bg-library-surface rounded-lg transition-colors relative group focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-offset-0 dark:focus:ring-offset-0"
                title="Afficher les notifications"
                aria-label="Notifications"
              >
                <Bell className="w-5 h-5" />
                <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-library-accent rounded-full border-2 border-library-surface group-hover:animate-pulse"></span>
              </button>
              {showNotifications && (
                <div className="absolute right-0 mt-2 w-80 z-50">
                  <NotificationCenter onClose={() => setShowNotifications(false)} />
                </div>
              )}
            </div>

            {/* Séparateur visuel - Visible sur tablette et desktop */}
            <div className="h-6 w-px bg-border mx-1 hidden sm:block"></div>

            {/* Sélecteur de thème (clair/sombre)
                - Composant réutilisable qui bascule entre les themes
                - Sauvegarde la préférence en localStorage */}
            <ThemeToggle />

            {/* Widget de profil utilisateur - Affiche avatar, prénom et statut
                - Avatar avec initiale du prénom
                - Affiche le statut (Premium/Gratuit)
                - Caché sur mobile pour économiser l'espace */}
            <div className="relative" ref={profileRef}>
              <button 
                onClick={() => setShowProfileMenu(v => !v)} 
                className="flex items-center gap-3 pl-2 pr-3 py-1.5 rounded-lg hover:bg-surface-weak dark:hover:bg-library-surface transition-colors border border-transparent hover:border-muted group focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-offset-0 dark:focus:ring-offset-0"
                title="Ouvrir le menu profil"
                aria-label="Menu profil"
              >
                <div className="w-9 h-9 rounded-full overflow-hidden shadow-sm bg-gradient-to-br from-library-primary to-library-accent dark:from-library-dark-accent dark:to-library-accent flex items-center justify-center">
                  {avatarUrl ? (
                    <img src={avatarUrl} alt={`${user?.firstName || user?.username || 'Utilisateur'} avatar`} className="w-full h-full object-cover" />
                  ) : (
                    <ApiImage
                      imageKey={user?.avatar}
                      src={user?.avatar && (user.avatar.startsWith('/') || user.avatar.startsWith('http')) ? user.avatar : undefined}
                      fallback={'/avatar-1.jpg'}
                      alt={`${user?.firstName || user?.username || 'Utilisateur'} avatar`}
                      className="w-full h-full object-cover"
                    />
                  )}
                </div>
                <div className="hidden sm:block text-left">
                  <p className="text-sm font-semibold text-primary dark:text-library-text leading-none">{user?.firstName || user?.username || 'Utilisateur'}</p>
                  <p className="text-xs text-muted dark:text-library-muted mt-0.5">{user?.isMember ? 'Premium' : 'Gratuit'}</p>
                </div>
                <ChevronRight className="w-4 h-4 text-muted dark:text-library-muted hidden sm:block group-hover:translate-x-0.5 transition-transform" />
              </button>
              {showProfileMenu && (
                <div className="absolute right-0 mt-2 w-56 z-50">
                  <ProfileMenu user={user} onClose={() => setShowProfileMenu(false)} />
                </div>
              )}
            </div>
            {/* Bouton menu hamburger
                - Visible seulement sur petits écrans (mobile)
                - Prêt à être connecté à un menu déroulant ou drawer
                - Utilise les classes responsive de Tailwind */}
            <button className="md:hidden p-2 text-muted dark:text-library-muted hover:bg-surface-weak dark:hover:bg-library-surface rounded-lg transition-colors">
              <Menu className="w-6 h-6" />
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
}

import { X, Check, Clock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import useNotifications from '@/hooks/useNotifications';

interface NotificationCenterProps {
  onClose?: () => void;
}

export function NotificationCenter({ onClose }: NotificationCenterProps) {
  const { notifications, loading, markAllRead, clearAll, markRead } = useNotifications();

  const toggleRead = (id: string, current: boolean) => {
    void markRead(id, !current);
  };

  return (
    <div className="surface rounded-lg shadow-lg p-3 border border-muted">
      <div className="flex items-center justify-between mb-3">
        <h4 className="font-semibold">Notifications</h4>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => void markAllRead()} 
            className="text-xs sm:text-sm text-muted hover:text-primary dark:hover:text-library-dark-accent focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-offset-0 dark:focus:ring-offset-0 rounded px-2 py-1 transition-colors"
            title="Marquer toutes les notifications comme lues"
          >
            Marquer lu
          </button>
          <button 
            onClick={() => void clearAll()} 
            className="text-xs sm:text-sm text-muted hover:text-primary dark:hover:text-library-dark-accent focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-offset-0 dark:focus:ring-offset-0 rounded px-2 py-1 transition-colors"
            title="Supprimer toutes les notifications"
          >
            <span className="hidden sm:inline">Tout supprimer</span>
            <span className="sm:hidden">Vider</span>
          </button>
          <button 
            onClick={onClose} 
            className="p-1 rounded hover:bg-surface-weak dark:hover:bg-library-dark-secondary focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-offset-0 dark:focus:ring-offset-0 transition-colors"
            title="Fermer les notifications"
            aria-label="Fermer"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="max-h-64 overflow-y-auto space-y-2">
        {loading && <div className="py-4 text-center text-sm text-muted">Chargement…</div>}
        {!loading && notifications.length === 0 && (
          <div className="py-6 text-center text-sm text-muted">Aucune notification</div>
        )}

        {notifications.map(n => (
          <div key={n.id} className={`p-3 rounded-lg transition-colors ${n.read ? 'bg-surface' : 'bg-library-accent/5'}`}>
            <div className="flex items-start justify-between gap-2">
              <div>
                <div className="font-medium text-sm">{n.title}</div>
                <div className="text-xs text-muted">{n.body}</div>
                <div className="text-[10px] text-muted mt-2 flex items-center gap-1"><Clock className="w-3 h-3" />{n.date}</div>
              </div>
              <div className="flex flex-col items-end gap-2">
                <button 
                  onClick={() => toggleRead(n.id, !!n.read)} 
                  className="p-1 rounded hover:bg-surface-weak dark:hover:bg-library-dark-secondary text-xs sm:text-sm text-muted focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-offset-0 dark:focus:ring-offset-0 transition-colors"
                  title={n.read ? 'Marquer comme non lu' : 'Marquer comme lu'}
                >
                  {n.read ? 'Non lu' : 'Lu'}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import { User, Settings, LogOut, ChevronRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import type { User as TUser } from '@/types';

interface ProfileMenuProps {
  user: TUser;
  onClose?: () => void;
}

export function ProfileMenu({ user, onClose }: ProfileMenuProps) {
  return (
    <div className="surface rounded-lg shadow-lg p-3 border border-muted">
      <div className="flex items-center gap-3 mb-3">
        <div className="w-10 h-10 rounded-full bg-library-primary/10 flex items-center justify-center font-bold">{user?.firstName?.[0] || 'U'}</div>
        <div>
          <div className="font-semibold">{user?.firstName} {user?.lastName}</div>
          <div className="text-xs text-muted">{user?.email}</div>
        </div>
      </div>

      <div className="flex flex-col divide-y border-t border-muted">
        <button 
          className="flex items-center justify-between py-2 px-1 hover:bg-surface-weak dark:hover:bg-library-dark-secondary focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-inset rounded transition-colors"
          onClick={() => {
            onClose?.();
            window.dispatchEvent(new CustomEvent('app:navigate', { detail: { view: 'profile' } }));
          }}
          title="Afficher votre profil"
        >
          <div className="flex items-center gap-2"><User className="w-4 h-4 flex-shrink-0" />Mon profil</div>
          <ChevronRight className="w-4 h-4 text-muted flex-shrink-0" />
        </button>
        <button 
          className="flex items-center justify-between py-2 px-1 hover:bg-surface-weak dark:hover:bg-library-dark-secondary focus:outline-none focus:ring-2 focus:ring-library-primary dark:focus:ring-library-dark-accent focus:ring-inset rounded transition-colors"
          onClick={() => {
            onClose?.();
            window.dispatchEvent(new CustomEvent('app:navigate', { detail: { view: 'settings' } }));
          }}
          title="Ouvrir les paramètres"
        >
          <div className="flex items-center gap-2"><Settings className="w-4 h-4 flex-shrink-0" />Paramètres</div>
          <ChevronRight className="w-4 h-4 text-muted flex-shrink-0" />
        </button>
        <button 
