import { useEffect, useState } from 'react';
import type { KeyboardEvent } from 'react';
import { Calendar, Star, ChevronRight, Flame, Sparkles, TrendingUp, Crown, Lock, Newspaper, Heart } from 'lucide-react';
import { Navbar } from '@/components/Navbar';
import { BottomNavigation } from '@/components/BottomNavigation';
import { ApiImage } from '@/components/ApiImage';
import { Button } from '@/components/ui/button';
import type { View, User, Book, Event, News } from '@/types';
import { useBooks, useEvents, useNews } from '@/hooks/useData';

interface HomePageProps {
  user: User;
  onNavigate: (view: View, params?: { bookId?: string; clubId?: string; eventId?: string; newsId?: string }) => void;
}

// ── SKELETONS ─────────────────────────────────────────────────────────

function SkeletonBookCard() {
  return (
    <div className="flex flex-col h-full">
      <div className="skeleton skeleton-book-cover mb-3" />
      <div className="space-y-2">
        <div className="skeleton skeleton-title" />
        <div className="skeleton skeleton-text w-3/4" />
        <div className="skeleton skeleton-badge w-12 mt-1" />
      </div>
    </div>
  );
}

function SkeletonEventCard() {
  return (
    <div className="surface rounded-xl p-3 border border-[var(--border-color)] flex items-center gap-4">
      <div className="skeleton w-14 h-14 rounded-xl flex-shrink-0" />
      <div className="flex-1 space-y-2">
        <div className="skeleton skeleton-text w-4/5" />
        <div className="skeleton skeleton-text-sm w-2/3" />
      </div>
    </div>
  );
}

function SkeletonNewsCard() {
  return (
    <div className="surface rounded-2xl overflow-hidden border border-[var(--border-color)]">
      <div className="skeleton w-full" style={{ aspectRatio: '16/9', borderRadius: 0 }} />
      <div className="p-4 space-y-3">
        <div className="skeleton skeleton-badge w-16" />
        <div className="skeleton skeleton-title" />
        <div className="skeleton skeleton-text" />
        <div className="skeleton skeleton-text w-4/5" />
      </div>
    </div>
  );
}

// ── PAGE ──────────────────────────────────────────────────────────────

export function HomePage({ user, onNavigate }: HomePageProps) {
  const [greeting, setGreeting] = useState('Bonjour');
  const [dataReady, setDataReady] = useState(false);
  const { books } = useBooks();
  const { events } = useEvents();
  const { news } = useNews();

  useEffect(() => {
    const hour = new Date().getHours();
    if (hour < 12) setGreeting('Bonjour');
    else if (hour < 18) setGreeting('Bon après-midi');
    else setGreeting('Bonsoir');
    const t = setTimeout(() => setDataReady(true), 700);
    return () => clearTimeout(t);
  }, []);

  const recommendedBooks = (user?.preferredGenres && user.preferredGenres.length > 0)
    ? books.filter(b => user.preferredGenres.includes(b.genre || '')).slice(0, 4)
    : books.slice(0, 4);
  const newBooks = books.filter(b => (b as any).is_new).slice(0, 4);
  const popularBooks = books.filter(b => (b as any).is_popular).slice(0, 4);
  const upcomingEvents = events.slice(0, 3);
  const latestNews = news.sort((a, b) => new Date(b.date || '').getTime() - new Date(a.date || '').getTime()).slice(0, 3);

  return (
    <div className="min-h-screen bg-library-bg pb-24 transition-colors duration-300">
      <Navbar user={user} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 pt-24">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* ── COLONNE PRINCIPALE ── */}
          <div className="lg:col-span-8 space-y-10">

            {/* Hero card */}
            <header className="relative overflow-hidden rounded-3xl gradient-hero border border-[var(--border-color)] shadow-card transition-all duration-300">
              <div className="absolute top-0 right-0 w-64 h-64 bg-[var(--library-accent)]/8 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none" />
              <div className="absolute bottom-0 left-0 w-48 h-48 bg-[var(--library-accent)]/5 rounded-full blur-2xl -ml-10 -mb-10 pointer-events-none" />
              <div className="relative p-8 md:p-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
                <div>
                  <p className="text-muted font-medium mb-1">{greeting},</p>
                  <h1 className="font-display text-3xl md:text-4xl font-bold mb-3 text-primary">
                    {user?.firstName || 'Utilisateur'} !
                  </h1>
                  <p className="text-muted max-w-md leading-relaxed">
                    {newBooks.length > 0 ? (
                      <>
                        <span className="font-semibold text-accent">{newBooks.length} {newBooks.length > 1 ? 'nouveaux livres' : 'nouveau livre'}</span> vient d'arriver au catalogue.{' '}
                        Votre prochain coup de cœur est peut-être là.
                      </>
                    ) : (
                      <>Le catalogue de la CAEB vous attend — 12 000 ouvrages pour tous les goûts.</>
                    )}
                  </p>
                  {!user?.isMember && (
                    <div className="mt-6">
                      <Button className="btn-solid shadow-soft hover:shadow-medium hover:-translate-y-0.5 transition-all font-semibold">
                        <Crown className="w-4 h-4 mr-2" />
                        Devenir Premium
                      </Button>
                    </div>
                  )}
                </div>
              </div>
            </header>

            {/* Actualités */}
            <section className="animate-slide-up">
              <SectionHeader title="Actualités" icon={Newspaper} onSeeAll={() => onNavigate('news')} />
              {!dataReady ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                  {[0, 1, 2].map(i => <SkeletonNewsCard key={i} />)}
                </div>
              ) : latestNews.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                   {latestNews.map((newsItem) => (
                    <NewsCard key={newsItem.id} news={newsItem} onClick={() => onNavigate('news-detail', { newsId: newsItem.id })} />
                  ))}
                </div>
              ) : null}
            </section>

            {/* Recommandés */}
            <section className="animate-slide-up">
              <SectionHeader title="Recommandé pour vous" icon={Sparkles} onSeeAll={() => onNavigate('catalog')} />
              {!dataReady ? (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 md:gap-6">
                  {[0, 1, 2, 3].map(i => <SkeletonBookCard key={i} />)}
                </div>
              ) : recommendedBooks.length > 0 ? (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 md:gap-6">
                  {recommendedBooks.map((book) => (
                    <BookCard key={book.id} book={book} user={user} onClick={() => onNavigate('book-detail', { bookId: book.id })}
                      onToggleFavorite={(id) => user.favorites?.includes(id) ? user.favorites = user.favorites.filter(f => f !== id) : user.favorites = [...(user.favorites || []), id]} />
                  ))}
                </div>
              ) : null}
            </section>

            {/* Nouveautés */}
            <section className="animate-slide-up" style={{ animationDelay: '100ms' }}>
              <SectionHeader title="Nouveautés" icon={TrendingUp} onSeeAll={() => onNavigate('catalog')} />
              {!dataReady ? (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 md:gap-6">
                  {[0, 1, 2, 3].map(i => <SkeletonBookCard key={i} />)}
                </div>
              ) : (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 md:gap-6">
                  {newBooks.map((book) => (
                    <BookCard key={book.id} book={book} user={user} onClick={() => onNavigate('book-detail', { bookId: book.id })}
                      onToggleFavorite={(id) => user.favorites?.includes(id) ? user.favorites = user.favorites.filter(f => f !== id) : user.favorites = [...(user.favorites || []), id]} />
                  ))}
                </div>
              )}
            </section>

            {/* Populaires */}
            <section className="animate-slide-up" style={{ animationDelay: '200ms' }}>
              <SectionHeader title="Les plus populaires" icon={Flame} onSeeAll={() => onNavigate('catalog')} />
              {!dataReady ? (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 md:gap-6">
                  {[0, 1, 2, 3].map(i => <SkeletonBookCard key={i} />)}
                </div>
              ) : (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4 md:gap-6">
                  {popularBooks.map((book) => (
                    <BookCard key={book.id} book={book} user={user} onClick={() => onNavigate('book-detail', { bookId: book.id })}
                      onToggleFavorite={(id) => user.favorites?.includes(id) ? user.favorites = user.favorites.filter(f => f !== id) : user.favorites = [...(user.favorites || []), id]} />
                  ))}
                </div>
              )}
            </section>
          </div>

          {/* ── SIDEBAR ── */}
          <div className="lg:col-span-4 space-y-8">
            <section className="animate-slide-up" style={{ animationDelay: '400ms' }}>
              <SectionHeader title="Agenda" icon={Calendar} onSeeAll={() => onNavigate('events')} />
              {!dataReady ? (
                <div className="space-y-3">
                  {[0, 1, 2].map(i => <SkeletonEventCard key={i} />)}
                </div>
              ) : (
                <div className="space-y-3">
                  {upcomingEvents.map((event) => (
                    <EventCard key={event.id} event={event} user={user} onClick={() => onNavigate('event-detail', { eventId: event.id })} />
                  ))}
                </div>
              )}
            </section>

            {!user?.isMember && (
              <div className="gradient-accent rounded-2xl p-6 text-center space-y-4 shadow-medium border border-[var(--library-accent)]/20 relative overflow-hidden">
                <div className="absolute inset-0 opacity-10 pointer-events-none">
                  <div className="absolute top-0 left-0 w-32 h-32 bg-white rounded-full blur-2xl" />
                </div>
                <div className="relative">
                  <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center mx-auto mb-3">
                    <Crown className="w-6 h-6 text-[var(--library-on-accent)]" />
                  </div>
                  <h3 className="font-bold text-lg text-on-accent">Devenez membre CAEB</h3>
                  <p className="text-on-accent/75 text-sm mt-1">Empruntez sans limite et participez à tous les événements.</p>
                  <Button className="mt-4 w-full bg-[var(--library-surface)] text-[var(--library-accent)] font-bold shadow-medium hover:shadow-elevated hover:-translate-y-0.5 transition-all">
                    Voir les offres
                  </Button>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>
      <BottomNavigation user={user} onNavigate={onNavigate} />
    </div>

  );
}

// ── SOUS-COMPOSANTS ──────────────────────────────────────────────────

function SectionHeader({ title, icon: Icon, onSeeAll }: { title: string; icon: any; onSeeAll?: () => void }) {
  return (
    <div className="flex items-center justify-between mb-5 px-1">
      <h2 className="font-display font-semibold text-xl text-primary flex items-center gap-2.5">
        <div className="p-1.5 bg-[var(--library-accent)]/10 border border-[var(--library-accent)]/20 rounded-lg">
          <Icon className="w-5 h-5 text-accent" />
        </div>
        {title}
      </h2>
      {onSeeAll && (
        <button onClick={onSeeAll}
          className="text-sm font-semibold text-accent hover:opacity-75 flex items-center gap-1 transition-opacity focus:outline-none focus:ring-2 focus:ring-[var(--library-accent)] focus:ring-offset-0 rounded px-2 py-1 tap-feedback">
          <span className="hidden sm:inline">Voir tout</span>
          <span className="sm:hidden">Plus</span>
          <ChevronRight className="w-4 h-4" />
        </button>
      )}
    </div>
  );
}

function BookCard({ book, user, onClick, onToggleFavorite }: { book: Book; user: User; onClick: () => void; onToggleFavorite?: (id: string) => void }) {
  const isFavorited = user.favorites?.includes(book.id) || false;
  const [heartPop, setHeartPop] = useState(false);

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onClick(); }
  };

  const handleFavorite = (e: React.MouseEvent) => {
    e.stopPropagation();
    setHeartPop(true);
    setTimeout(() => setHeartPop(false), 400);
    onToggleFavorite?.(book.id);
  };

  return (
    <div role="button" tabIndex={0} onClick={onClick} onKeyDown={handleKeyDown}
      className="w-full text-left group relative flex flex-col h-full book-card-3d cursor-pointer">
      <div className="relative aspect-[2/3] w-full rounded-2xl overflow-hidden shadow-card mb-3 surface-weak">
        <ApiImage src={book.cover} alt={book.title}
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />

        {/* Favoris avec pop */}
        <button onClick={handleFavorite}
          className="absolute top-2 right-2 p-2 rounded-full surface shadow-soft hover:shadow-medium focus:outline-none focus:ring-2 focus:ring-red-500/50"
          style={{ transform: heartPop ? 'scale(1.35)' : 'scale(1)', transition: 'transform 0.35s cubic-bezier(0.34, 1.56, 0.64, 1)' }}
          aria-label={isFavorited ? 'Retirer des favoris' : 'Ajouter aux favoris'}>
          <Heart className={`w-4 h-4 transition-colors ${isFavorited ? 'fill-red-500 text-red-500' : 'text-muted'}`} />
        </button>

        {/* Lock overlay */}
        {!user?.isMember && !book.isAvailable && (
          <div className="absolute inset-0 surface/80 backdrop-blur-[2px] flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
            <div className="surface p-2 rounded-full shadow-medium">
              <Lock className="w-4 h-4 text-accent" />
            </div>
          </div>
        )}
      </div>

      <div className="flex-1 flex flex-col">
        <h3 className="font-bold text-primary line-clamp-1 group-hover:text-accent transition-colors text-base">{book.title}</h3>
        <p className="text-sm text-muted line-clamp-1 mb-1">{book.author}</p>
        {/* Étoiles cascade */}
        <div className="mt-auto flex items-center justify-between">
          <div className="flex items-center gap-0.5 star-cascade">
            {[1,2,3,4,5].map(n => (
              <Star key={n}
                className={`star w-3 h-3 ${n <= Math.round(book.rating || 4.5) ? 'fill-[var(--library-accent)] text-[var(--library-accent)]' : 'text-[var(--border-color)]'}`} />
            ))}
            <span className="text-xs font-semibold text-accent ml-1">{book.rating || '4.5'}</span>
          </div>
          {!user?.isMember && (
            <span className="text-[10px] font-bold text-accent bg-[var(--library-accent)]/10 px-2 py-0.5 rounded-full">PREMIUM</span>
          )}
        </div>
      </div>
    </div>
  );
}

function EventCard({ event, user, onClick }: { event: Event; user: User; onClick: () => void }) {
  const eventDate = new Date(event.date);
  return (
    <button onClick={onClick}
      className="w-full surface rounded-xl p-3 shadow-card border border-[var(--border-color)] hover:shadow-card-hover hover:border-[var(--library-accent)]/25 transition-all duration-300 text-left flex items-center gap-4 group tap-feedback">
      <div className="w-14 h-14 surface-alt rounded-xl border border-[var(--border-color)] flex flex-col items-center justify-center flex-shrink-0 group-hover:bg-[var(--library-accent)]/10 group-hover:border-[var(--library-accent)]/30 transition-all">
        <span className="text-[10px] text-muted font-bold uppercase tracking-wider">
          {eventDate.toLocaleDateString('fr-FR', { month: 'short' })}
        </span>
        <span className="text-xl font-bold text-primary group-hover:text-accent transition-colors">
          {eventDate.getDate()}
        </span>
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-0.5">
          <h3 className="font-semibold text-primary truncate group-hover:text-accent transition-colors">{event.title}</h3>
          {!user.isMember && event.type === 'conference' && <Lock className="w-3 h-3 text-muted flex-shrink-0" />}
        </div>
        <div className="flex items-center text-xs text-muted gap-2">
          <span>{event.time}</span>
          <span className="w-1 h-1 bg-[var(--border-color)] rounded-full" />
          <span className="truncate max-w-[100px]">{event.location}</span>
        </div>
      </div>
    </button>
  );
}

function NewsCard({ news, onClick }: { news: News; onClick: () => void }) {
  const newsDate = new Date(news.date);

  const categoryConfig: Record<string, { label: string; class: string }> = {
    announcement: { label: 'Annonce', class: 'bg-[var(--library-accent)]/10 text-accent border-[var(--library-accent)]/20' },
    event: { label: 'Événement', class: 'bg-purple-500/10 text-purple-500 border-purple-500/20' },
    course: { label: 'Formation', class: 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' },
    visit: { label: 'Visite', class: 'bg-orange-500/10 text-orange-500 border-orange-500/20' },
    closure: { label: 'Fermeture', class: 'bg-red-500/10 text-red-500 border-red-500/20' },
    general: { label: 'Actualité', class: 'surface-weak text-muted border-[var(--border-color)]' },
  };

  const config = categoryConfig[news.category] || categoryConfig.general;

  return (
    <button onClick={onClick} className="w-full text-left group flex flex-col h-full tap-feedback">
      <div className="surface rounded-2xl overflow-hidden shadow-card hover:shadow-card-hover border border-[var(--border-color)] hover:border-[var(--library-accent)]/20 transition-all duration-300 flex flex-col h-full">
        {news.image && (
          <div className="relative w-full aspect-video overflow-hidden bg-[var(--library-surface-alt)]">
            <ApiImage src={news.image} alt={news.title}
              className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
          </div>
        )}
        <div className="flex flex-col flex-1 p-4 md:p-5">
          <div className="flex items-center justify-between mb-3 gap-2">
            <span className="text-xs font-medium text-muted whitespace-nowrap ml-auto">
              {newsDate.getDate()} {newsDate.toLocaleDateString('fr-FR', { month: 'short' })}
            </span>
          </div>
          <h3 className="font-bold text-primary line-clamp-2 group-hover:text-accent transition-colors mb-2 text-base">{news.title}</h3>
          <p className="text-sm text-muted line-clamp-3 mb-4 flex-1">{news.excerpt}</p>
          <div className="flex items-center text-sm font-semibold text-accent gap-0.5 hover:gap-1 transition-all">
            En savoir plus <ChevronRight className="w-4 h-4" />
          </div>
        </div>
      </div>
    </button>
  );

}

// Page de détails d'une actualité
import { ChevronLeft, Calendar, Share2, ArrowRight } from 'lucide-react';
import { Navbar } from '@/components/Navbar';
import { ApiImage } from '@/components/ApiImage';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import type { User, News } from '@/types';
import { useNews } from '@/hooks/useData';
import { toast } from 'sonner';

interface NewsDetailPageProps {
  newsId: string;
  user: User | null;
  onBack: () => void;
}

export function NewsDetailPage({ newsId, user, onBack }: NewsDetailPageProps) {
  const { news } = useNews();
  const newsItem = news.find(n => n.id === newsId);

  const categoryLabels: Record<string, string> = {
    announcement: 'Annonce',
    event: 'Événement',
    course: 'Formation',
    visit: 'Visite',
    closure: 'Fermeture',
    general: 'Actualité',
  };

  // Category badge styles using design tokens
  const categoryColors: Record<string, string> = {
    announcement: 'bg-[var(--library-accent)]/10 text-[var(--library-accent)] border-[var(--library-accent)]/20',
    event:        'bg-purple-500/10 text-purple-500 border-purple-500/20',
    course:       'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
    visit:        'bg-orange-500/10 text-orange-500 border-orange-500/20',
    closure:      'bg-red-500/10 text-red-500 border-red-500/20',
    general:      'bg-[var(--library-surface-alt)] text-[var(--library-muted)] border-[var(--border-color)]',
  };

  const handleShare = () => {
    toast.success('Lien copié dans le presse-papiers !');
  };

  if (!newsItem) {
    return (
      <div className="min-h-screen bg-library-bg adaptive-fg pb-24">
        <Navbar user={user} />
        <main className="max-w-4xl mx-auto px-4 py-8 pt-24">
          <button
            onClick={onBack}
            className="flex items-center gap-2 text-[var(--library-accent)] mb-6 hover:opacity-80 transition-all focus:outline-none focus:ring-2 focus:ring-[var(--library-accent)]/30 rounded px-2 py-1"
            title="Retour aux actualités"
            aria-label="Retour"
          >
            <ChevronLeft className="w-5 h-5" />
            Retour
          </button>
          <div className="surface rounded-2xl p-8 text-center border border-[var(--border-color)]">
            <p className="text-[var(--library-muted)]">Actualité non trouvée</p>
          </div>
        </main>
      </div>
    );
  }

  const newsDate = new Date(newsItem.date);

  return (
    <div className="min-h-screen bg-library-bg adaptive-fg pb-24">
      <Navbar user={user} />

      <main className="max-w-4xl mx-auto px-4 py-8 pt-24">
        {/* Back button */}
        <button
          onClick={onBack}
          className="flex items-center gap-2 text-[var(--library-accent)] mb-6 hover:opacity-80 transition-all focus:outline-none focus:ring-2 focus:ring-[var(--library-accent)]/30 rounded px-2 py-1"
          title="Retour aux actualités"
          aria-label="Retour aux actualités"
        >
          <ChevronLeft className="w-5 h-5" />
          <span className="hidden sm:inline">Retour aux actualités</span>
          <span className="sm:hidden">Retour</span>
        </button>

        {/* Article card */}
