                      )}
                    </div>
                  )}
                </section>

                {/* Explication du score — visible uniquement si profil incomplet */}
                {scoreConfiance < 0.6 && (
                  <section>
                    <h3 className="font-display font-semibold text-lg text-primary mb-4">
                      Améliorer mes recommandations
                    </h3>
                    <div className="space-y-3">
                      {!user.educationLevel && (
                        <TipItem text="Renseignez votre niveau d'études dans votre profil (+20 % sur le score de confiance)" />
                      )}
                      {!user.preferredGenres?.[0] && (
                        <TipItem text="Choisissez un genre préféré pour activer les recommandations par contenu (CB)" />
                      )}
                      {!(user as unknown as Record<string, string>).sous_genre_prefere && (
                        <TipItem text="Ajoutez un sous-genre pour affiner encore davantage vos suggestions" />
                      )}
                      {stats.reviewsPosted < 5 && !user.isMember && (
                        <TipItem text={`Publiez ${5 - stats.reviewsPosted} avis supplémentaire${5 - stats.reviewsPosted > 1 ? 's' : ''} pour renforcer votre profil`} />
                      )}
                      {user.isMember && stats.booksRead < 5 && (
                        <TipItem text={`${5 - stats.booksRead} emprunt${5 - stats.booksRead > 1 ? 's' : ''} supplémentaire${5 - stats.booksRead > 1 ? 's' : ''} pour activer toutes les sources de recommandation`} />
                      )}
                    </div>
                  </section>
                )}
              </TabsContent>

              {/* ── PARAMÈTRES ── */}
              <TabsContent value="settings" className="space-y-3">
                <SettingItem icon={Edit3}       title="Modifier mon profil"  description="Nom, niveau, genre préféré, sous-genre"       onClick={() => toast.info('À venir')} />
                <SettingItem icon={Bell}        title="Notifications"        description="Rappels de retour, livres disponibles"          onClick={() => toast.info('À venir')} />
                <SettingItem icon={Shield}      title="Confidentialité"      description="Visibilité du profil et gestion des données"    onClick={() => toast.info('À venir')} />
                <SettingItem icon={HelpCircle}  title="Aide & Contact"       description="FAQ, horaires et comment nous joindre"          onClick={() => toast.info('À venir')} />

                {onToggleMemberStatus && (
                  <div className="pt-3 border-t border-[var(--border-color)]">
                    <p className="text-xs text-muted mb-2 px-1">Mode démonstration</p>
                    <Button
                      onClick={onToggleMemberStatus}
                      variant="outline"
                      className="w-full border-[var(--library-accent)]/30 text-accent hover:bg-[var(--library-accent)]/10 font-semibold tap-feedback"
                    >
                      <Crown className="w-4 h-4 mr-2" />
                      {user.isMember ? 'Passer en mode Non-membre' : 'Passer en mode Membre'}
                    </Button>
                  </div>
                )}
              </TabsContent>
            </Tabs>
          </div>
        </div>
      </main>
      <BottomNavigation user={user} onNavigate={onNavigate} />
    </div>
  );
}

// ── Sous-composants ───────────────────────────────────────────────────

function StatCard({ icon: Icon, value, label }: {
  icon: React.ComponentType<{ className?: string }>;
  value: number;
  label: string;
}) {
  return (
    <div className="surface rounded-xl p-4 shadow-card border border-[var(--border-color)] hover:shadow-card-hover transition-shadow flex flex-col items-center text-center gap-2">
      <div className="w-10 h-10 bg-[var(--library-accent)]/10 border border-[var(--library-accent)]/20 rounded-full flex items-center justify-center">
        <Icon className="w-5 h-5 text-accent" />
      </div>
      <div>
        <p className="text-2xl font-bold text-primary">{value}</p>
        <p className="text-xs text-muted mt-0.5">{label}</p>
      </div>
    </div>
  );
}

function ActivityItem({ icon: Icon, title, description, color }: {
  icon: React.ComponentType<{ className?: string }>;
  title: string;
  description: string;
  color: 'accent' | 'amber';
}) {
  const cls = color === 'amber'
    ? 'bg-amber-500/10 border-amber-500/20 text-amber-500'
    : 'bg-[var(--library-accent)]/10 border-[var(--library-accent)]/20 text-accent';

  return (
    <div className="flex items-start gap-4 surface rounded-xl border border-[var(--border-color)] shadow-card p-4">
      <div className={`w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0 border ${cls}`}>
        <Icon className="w-5 h-5" />
      </div>
      <div className="flex-1 min-w-0">
        <h4 className="font-semibold text-primary">{title}</h4>
        <p className="text-sm text-muted mt-0.5">{description}</p>
      </div>
    </div>
  );
}

function TipItem({ text }: { text: string }) {
  return (
    <div className="flex items-start gap-3 surface-alt rounded-xl border border-[var(--library-accent)]/15 p-4">
      <TrendingUp className="w-4 h-4 text-accent flex-shrink-0 mt-0.5" />
      <p className="text-sm text-muted">{text}</p>
    </div>
  );
}

function SettingItem({ icon: Icon, title, description, onClick }: {
  icon: React.ComponentType<{ className?: string }>;
  title: string;
  description: string;
  onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
      className="w-full surface rounded-xl border border-[var(--border-color)] shadow-card hover:shadow-card-hover hover:border-[var(--library-accent)]/25 transition-all p-4 flex items-center gap-4 tap-feedback"
    >
      <div className="w-10 h-10 bg-[var(--library-accent)]/10 border border-[var(--library-accent)]/20 rounded-lg flex items-center justify-center flex-shrink-0">
        <Icon className="w-5 h-5 text-accent" />
      </div>
      <div className="flex-1 text-left">
        <h4 className="font-semibold text-primary">{title}</h4>
        <p className="text-sm text-muted">{description}</p>
      </div>
      <ChevronRight className="w-5 h-5 text-muted flex-shrink-0" />
    </button>
  );
}

// Page de recherche globale — CAEB Design System
import { Search, BookOpen, Users, Calendar, Newspaper, X } from 'lucide-react';
import { Navbar } from '@/components/Navbar';
import { ApiImage } from '@/components/ApiImage';
import { Badge } from '@/components/ui/badge';
import type { User } from '@/types';
import { useState, useMemo } from 'react';
import { useBooks, useClubs, useEvents, useNews } from '@/hooks/useData';

interface SearchPageProps {
  user: User | null;
  onNavigate: (view: any, params?: any) => void;
}

export function SearchPage({ user, onNavigate }: SearchPageProps) {
  const [query, setQuery] = useState('');
  const { books } = useBooks();
  const { clubs } = useClubs();
  const { events } = useEvents();
  const { news } = useNews();

  const results = useMemo(() => {
    if (!query.trim()) return { books: [], clubs: [], events: [], news: [] };
    const q = query.toLowerCase();
    return {
      books: books.filter(b => b.title.toLowerCase().includes(q) || b.author.toLowerCase().includes(q) || b.genre.toLowerCase().includes(q)).slice(0, 5),
      clubs: clubs.filter(c => c.name.toLowerCase().includes(q) || c.description.toLowerCase().includes(q)).slice(0, 5),
      events: events.filter(e => e.title.toLowerCase().includes(q) || e.description.toLowerCase().includes(q)).slice(0, 5),
      news: news.filter(n => n.title.toLowerCase().includes(q) || n.excerpt.toLowerCase().includes(q)).slice(0, 5),
    };
  }, [query, books, clubs, events, news]);

  const hasResults = Object.values(results).some(arr => arr.length > 0);

  const SectionTitle = ({ icon: Icon, label, count }: { icon: any; label: string; count: number }) => (
    <div className="flex items-center gap-2.5 mb-4">
      <div className="p-1.5 bg-[var(--library-accent)]/10 border border-[var(--library-accent)]/20 rounded-lg">
        <Icon className="w-4 h-4 text-accent" />
      </div>
      <h2 className="text-xl font-bold text-primary">{label}</h2>
      <span className="text-sm text-muted font-medium">({count})</span>
    </div>
  );

  return (
    <div className="min-h-screen bg-library-bg pb-24">
      <Navbar user={user} />

      <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8 pt-24">

        {/* Barre de recherche */}
        <div className="mb-10">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-accent pointer-events-none" />
            <input
              type="text"
              placeholder="Rechercher des livres, clubs, événements, actualités..."
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="w-full h-14 pl-12 pr-12 surface border border-[var(--border-color)] rounded-2xl text-primary placeholder:text-muted focus:outline-none focus:border-[var(--library-accent)] focus:ring-2 focus:ring-[var(--library-accent)]/20 shadow-card transition-all text-base"
            />
            {query && (
              <button onClick={() => setQuery('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-1.5 text-muted hover:text-accent rounded-lg transition-colors focus:outline-none"
                aria-label="Effacer">
                <X className="w-5 h-5" />
              </button>
            )}
          </div>
        </div>

        {/* Résultats */}
        {query.trim() ? (
          <div className="space-y-10">
            {results.books.length > 0 && (
              <section>
                <SectionTitle icon={BookOpen} label="Livres" count={results.books.length} />
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-4">
                  {results.books.map(book => (
                    <button key={book.id} onClick={() => onNavigate('book-detail', { bookId: book.id })}
                      className="group text-left">
                      <div className="relative aspect-[2/3] rounded-xl overflow-hidden surface-weak shadow-card hover:shadow-card-hover transition-all mb-2">
                        <ApiImage src={book.cover} alt={book.title}
                          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                      </div>
                      <h3 className="font-semibold text-sm text-primary line-clamp-2 group-hover:text-accent transition-colors">{book.title}</h3>
                      <p className="text-xs text-muted">{book.author}</p>
                    </button>
                  ))}
                </div>
              </section>
            )}

            {results.clubs.length > 0 && (
              <section>
                <SectionTitle icon={Users} label="Clubs" count={results.clubs.length} />
                <div className="space-y-3">
                  {results.clubs.map(club => (
                    <button key={club.id} onClick={() => onNavigate('club-detail', { clubId: club.id })}
                      className="w-full surface rounded-xl p-4 shadow-card hover:shadow-card-hover border border-[var(--border-color)] hover:border-[var(--library-accent)]/25 transition-all text-left group">
                      <h3 className="font-semibold text-primary group-hover:text-accent transition-colors mb-1">{club.name}</h3>
                      <p className="text-sm text-muted line-clamp-2">{club.description}</p>
                      <p className="text-xs text-accent font-semibold mt-2">{club.memberCount} membres</p>
                    </button>
                  ))}
                </div>
              </section>
            )}

            {results.events.length > 0 && (
              <section>
                <SectionTitle icon={Calendar} label="Événements" count={results.events.length} />
                <div className="space-y-3">
                  {results.events.map(event => (
                    <button key={event.id} onClick={() => onNavigate('event-detail', { eventId: event.id })}
                      className="w-full surface rounded-xl p-4 shadow-card hover:shadow-card-hover border border-[var(--border-color)] hover:border-[var(--library-accent)]/25 transition-all text-left group">
                      <div className="flex items-start justify-between gap-2 mb-1">
                        <h3 className="font-semibold text-primary group-hover:text-accent transition-colors flex-1">{event.title}</h3>
                        <Badge className="flex-shrink-0 text-xs bg-[var(--library-accent)]/10 text-accent border border-[var(--library-accent)]/20">
                          {event.type === 'conference' ? 'Conférence' : event.type === 'workshop' ? 'Atelier' : 'Événement'}
                        </Badge>
                      </div>
                      <p className="text-sm text-muted">{new Date(event.date).toLocaleDateString('fr-FR')} à {event.time}</p>
                    </button>
                  ))}
                </div>
              </section>
            )}

            {results.news.length > 0 && (
              <section>
                <SectionTitle icon={Newspaper} label="Actualités" count={results.news.length} />
                <div className="space-y-3">
                  {results.news.map(newsItem => (
                    <button key={newsItem.id} onClick={() => onNavigate('news-detail', { newsId: newsItem.id })}
                      className="w-full surface rounded-xl p-4 shadow-card hover:shadow-card-hover border border-[var(--border-color)] hover:border-[var(--library-accent)]/25 transition-all text-left group">
                      <h3 className="font-semibold text-primary group-hover:text-accent transition-colors mb-1">{newsItem.title}</h3>
                      <p className="text-sm text-muted line-clamp-2">{newsItem.excerpt}</p>
                      <p className="text-xs text-accent font-semibold mt-2">{new Date(newsItem.date).toLocaleDateString('fr-FR')}</p>
                    </button>
                  ))}
                </div>
              </section>
            )}

            {!hasResults && (
              <div className="text-center py-16">
                <div className="w-16 h-16 surface-alt border border-[var(--border-color)] rounded-full flex items-center justify-center mx-auto mb-4">
                  <Search className="w-8 h-8 text-muted opacity-50" />
                </div>
                <h3 className="text-lg font-semibold text-primary mb-2">Aucun résultat pour « {query} »</h3>
                <p className="text-muted">Vérifiez l'orthographe ou essayez un mot-clé différent</p>
              </div>
            )}
          </div>
        ) : (
          <div className="text-center py-20">
            <div className="w-20 h-20 bg-[var(--library-accent)]/10 border border-[var(--library-accent)]/20 rounded-full flex items-center justify-center mx-auto mb-5">
              <Search className="w-10 h-10 text-accent opacity-60" />
            </div>
            <h2 className="text-xl font-semibold text-primary mb-2">Que cherchez-vous ?</h2>
            <p className="text-muted max-w-xs mx-auto">Tapez un titre, un auteur, le nom d'un club ou d'un événement pour commencer</p>
          </div>
        )}
      </main>
    </div>
  );
}

// SettingsPage.tsx — CAEB Design System
import { Settings, Moon, Sun, Bell, Lock, LogOut } from 'lucide-react';
import { Navbar } from '@/components/Navbar';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import type { User } from '@/types';
import { useState } from 'react';
import { toast } from 'sonner';

interface SettingsPageProps {
  user: User | null;
  onLogout: () => void;
}

export function SettingsPage({ user, onLogout }: SettingsPageProps) {
  const [darkMode, setDarkMode] = useState(() => document.documentElement.classList.contains('dark'));
  const [notifications, setNotifications] = useState(true);
  const [emailNotifications, setEmailNotifications] = useState(true);

  const handleToggleDarkMode = () => {
    const next = !darkMode;
    setDarkMode(next);
    document.documentElement.classList.toggle('dark', next);
    toast.success(next ? 'Mode sombre activé' : 'Mode clair activé');
  };

  const handleLogout = () => { toast.success('À bientôt !'); onLogout(); };
  const handleSaveSettings = () => { toast.success('Paramètres enregistrés'); };

  if (!user) {
    return (
      <div className="min-h-screen bg-library-bg pb-24">
        <Navbar user={user} />
        <main className="max-w-4xl mx-auto px-4 py-8 pt-24">
          <div className="surface rounded-2xl p-8 text-center border border-[var(--border-color)]">
            <p className="text-muted">Veuillez vous connecter pour accéder aux paramètres</p>
          </div>
        </main>
      </div>
    );
  }

  const Toggle = ({ active, onToggle }: { active: boolean; onToggle: () => void }) => (
    <button onClick={onToggle} aria-pressed={active}
      className={`relative w-11 h-6 rounded-full transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-[var(--library-accent)] focus:ring-offset-2 ${active ? 'bg-[var(--library-accent)]' : 'bg-[var(--border-color)]'}`}>
      <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-soft transition-transform duration-300 ${active ? 'translate-x-5' : 'translate-x-0'}`} />
    </button>
  );

  const SectionTitle = ({ icon: Icon, title }: { icon?: any; title: string }) => (
    <h2 className="text-xl font-bold text-primary mb-6 flex items-center gap-2.5">
      {Icon ? <Icon className="w-5 h-5 text-accent" /> : <span className="w-4 h-4 rounded bg-[var(--library-accent)]" />}
      {title}
    </h2>
  );

  const InfoRow = ({ label, value }: { label: string; value: React.ReactNode }) => (
    <div className="flex items-center justify-between p-4 surface-alt rounded-xl border border-[var(--border-color)]">
      <div>
        <p className="text-xs text-muted font-semibold uppercase tracking-wider mb-0.5">{label}</p>
        <p className="text-primary font-semibold">{value}</p>
      </div>
    </div>
  );

  const ToggleRow = ({ label, active, onToggle }: { label: string; active: boolean; onToggle: () => void }) => (
    <div className="flex items-center justify-between p-4 surface-alt rounded-xl border border-[var(--border-color)]">
      <span className="font-semibold text-primary">{label}</span>
      <Toggle active={active} onToggle={onToggle} />
    </div>
  );

  return (
    <div className="min-h-screen bg-library-bg pb-24">
      <Navbar user={user} />
      <main className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8 pt-24">

        <div className="mb-8">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[var(--library-accent)]/10 border border-[var(--library-accent)]/20 rounded-xl flex items-center justify-center">
              <Settings className="w-5 h-5 text-accent" />
            </div>
            <h1 className="text-3xl md:text-4xl font-bold text-primary">Paramètres</h1>
          </div>
          <p className="text-muted pl-1">Personnalisez votre expérience et gérez votre compte</p>
        </div>

        <div className="space-y-5">
          {/* Compte */}
          <section className="surface rounded-2xl p-6 shadow-card border border-[var(--border-color)]">
            <SectionTitle title="Informations du compte" />
            <div className="space-y-3">
              <InfoRow label="Nom d'utilisateur" value={`${user.firstName} ${user.lastName}`} />
              <InfoRow label="Email" value={user.email} />
              <InfoRow label="Statut" value={
                <Badge className={user.isMember
                  ? 'bg-[var(--library-accent)]/15 text-accent border border-[var(--library-accent)]/30'
                  : 'surface-weak text-muted border border-[var(--border-color)]'}>
                  {user.isMember ? '✦ Premium' : 'Gratuit'}
                </Badge>
              } />
            </div>
          </section>

          {/* Apparence */}
          <section className="surface rounded-2xl p-6 shadow-card border border-[var(--border-color)]">
            <SectionTitle title="Apparence" />
            <button onClick={handleToggleDarkMode}
              className="w-full flex items-center justify-between p-4 surface-alt rounded-xl border border-[var(--border-color)] hover:border-[var(--library-accent)]/30 transition-all focus:outline-none focus:ring-2 focus:ring-[var(--library-accent)]">
              <div className="flex items-center gap-3">
                {darkMode
                  ? <Moon className="w-5 h-5 text-accent" />
                  : <Sun className="w-5 h-5 text-accent" />}
                <div className="text-left">
                  <p className="font-semibold text-primary">Mode sombre</p>
                  <p className="text-xs text-muted">{darkMode ? 'Palette Chocolat & Or — activé' : 'Palette Bleu & Blanc — activé'}</p>
                </div>
              </div>
              <div className={`relative w-11 h-6 rounded-full transition-colors duration-300 ${darkMode ? 'bg-[var(--library-accent)]' : 'bg-[var(--border-color)]'}`}>
                <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-soft transition-transform duration-300 ${darkMode ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </button>
          </section>

          {/* Notifications */}
          <section className="surface rounded-2xl p-6 shadow-card border border-[var(--border-color)]">
            <SectionTitle icon={Bell} title="Notifications" />
            <div className="space-y-3">
              <ToggleRow label="Notifications dans l'app" active={notifications} onToggle={() => setNotifications(!notifications)} />
              <ToggleRow label="Notifications par email" active={emailNotifications} onToggle={() => setEmailNotifications(!emailNotifications)} />
            </div>
          </section>

          {/* Sécurité */}
          <section className="surface rounded-2xl p-6 shadow-card border border-[var(--border-color)]">
            <SectionTitle icon={Lock} title="Sécurité" />
            <div className="space-y-3">
              <Button variant="outline" className="w-full justify-start gap-2 border-[var(--border-color)] text-primary hover:border-[var(--library-accent)]/30 font-semibold">
                <Lock className="w-4 h-4 text-accent flex-shrink-0" />Changer le mot de passe
              </Button>
              <Button variant="outline" className="w-full justify-start gap-2 border-[var(--border-color)] text-primary hover:border-[var(--library-accent)]/30 font-semibold">
                Appareils connectés
              </Button>
            </div>
          </section>

          {/* Actions */}
          <div className="flex flex-col sm:flex-row gap-3 pt-2">
            <Button onClick={handleSaveSettings}
              className="btn-solid flex-1 font-bold shadow-medium hover:shadow-elevated hover:-translate-y-0.5 transition-all sheen relative overflow-hidden">
              Enregistrer les paramètres
            </Button>
            <Button onClick={handleLogout} variant="destructive"
              className="flex-1 gap-2 font-bold hover:-translate-y-0.5 transition-all">
              <LogOut className="w-4 h-4" />Se déconnecter
            </Button>
          </div>
        </div>
      </main>
    </div>
  );
}
